#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int sum = 0;
        for (int i = 0; i < n; i++) {
            sum += arr[i];
        }
        int left_sum = 0;
        int flag = 0;
        for (int i = 0; i < n; i++) {
            if (left_sum == sum - left_sum - arr[i]) {
                printf("%d\n", i + 1);
                flag = 1;
                break;
            }
            left_sum += arr[i];
        }
        if (!flag) {
            printf("-1\n");
        }
    }
    return 0;
}

